<section class="auth-shell container"><div class="auth-card setup-card"><span class="eyebrow">First-time setup</span><h1>Create the owner account</h1><p>This page closes permanently after the first owner is created.</p><form method="post" class="form-stack"><?= csrf_field() ?><label>Owner name<input name="name" required></label><label>Email<input type="email" name="email" required></label><label>Phone<input type="tel" name="phone"></label><label>Strong password <small>At least 12 characters</small><input type="password" name="password" minlength="12" required></label><button class="button button-primary button-wide" type="submit">Create owner account<i data-lucide="shield-check"></i></button></form></div></section>

